import Callout from "../../../components/docs/Callout.astro";

You want to conditionally render UI based on connection, provider, and error states.

### Positive gates

Gates render their children only when a condition is met. They accept fallback props for each negative state.

**ArlopassConnectionGate**

Renders children when connected. Shows `fallback` while connecting, `notInstalledFallback` if the extension isn't detected, and `errorFallback` on failure.

```tsx title="ConnectionGate.tsx"
import { ArlopassProvider, ArlopassConnectionGate } from "@arlopass/react";

function App() {
  return (
    <ArlopassProvider appId="my-app">
      <ArlopassConnectionGate
        fallback={<p>Connecting to Arlopass extension...</p>}
        notInstalledFallback={
          <div>
            <h2>Extension Required</h2>
            <p>Install the Arlopass browser extension to use this app.</p>
            <a href="https://arlopass.com/install">Install Extension</a>
          </div>
        }
        errorFallback={({ error, retry }) => (
          <div>
            <p>Connection failed: {error.message}</p>
            {retry && <button onClick={retry}>Retry</button>}
          </div>
        )}
      >
        <MainApp />
      </ArlopassConnectionGate>
    </ArlopassProvider>
  );
}
```

**ArlopassProviderGate**

Renders children when a provider is selected. Shows `fallback` if no provider is chosen yet.

```tsx title="ProviderGate.tsx"
import { ArlopassProviderGate } from "@arlopass/react";

function ConnectedApp() {
  return (
    <ArlopassProviderGate
      fallback={
        <div>
          <h2>Select a Provider</h2>
          <p>
            Open the Arlopass extension popup and choose an AI provider before
            using the chat.
          </p>
        </div>
      }
    >
      <Chat />
    </ArlopassProviderGate>
  );
}
```

**ArlopassChatReadyGate**

Combines connection and provider checks in a single gate. This is the most common gate for chat UIs — it handles not-installed, connecting, no-provider, and error states.

```tsx title="ChatReadyGate.tsx"
import { ArlopassChatReadyGate } from "@arlopass/react";

// ArlopassChatReadyGate combines connection + provider checks in one gate
function App() {
  return (
    <ArlopassChatReadyGate
      connectingFallback={<p>Connecting...</p>}
      notInstalledFallback={
        <div>
          <p>Arlopass extension not detected.</p>
          <a href="https://arlopass.com/install">Install</a>
        </div>
      }
      providerFallback={<p>Please select a provider.</p>}
      errorFallback={({ error, retry }) => (
        <div>
          <p>Error: {error.message}</p>
          {retry && <button onClick={retry}>Retry</button>}
        </div>
      )}
    >
      <Chat />
    </ArlopassChatReadyGate>
  );
}
```

### Negative guards

Negative guards render only when a specific negative condition is true. Use them in headers, sidebars, or any area outside your main content gates.

```tsx title="NegativeGuards.tsx"
import {
  ArlopassNotInstalled,
  ArlopassDisconnected,
  ArlopassConnected,
  ArlopassProviderNotReady,
  ArlopassHasError,
  ArlopassChatNotReady,
  ArlopassChatReady,
} from "@arlopass/react";

function AppHeader() {
  return (
    <header style={{ display: "flex", gap: 16, alignItems: "center" }}>
      <h1>My App</h1>

      {/* Show install prompt when extension is missing */}
      <ArlopassNotInstalled>
        <a href="https://arlopass.com/install">Install Arlopass</a>
      </ArlopassNotInstalled>

      {/* Show reconnect button when disconnected */}
      <ArlopassDisconnected>
        <span style={{ color: "orange" }}>Disconnected</span>
      </ArlopassDisconnected>

      {/* Show green dot when connected */}
      <ArlopassConnected>
        <span style={{ color: "green" }}>Connected</span>
      </ArlopassConnected>

      {/* Prompt to select provider when none is chosen */}
      <ArlopassProviderNotReady>
        <span>Select a provider →</span>
      </ArlopassProviderNotReady>

      {/* Show errors in the header */}
      <ArlopassHasError>
        {({ error, retry }) => (
          <span style={{ color: "red" }}>
            {error.message}
            {retry && <button onClick={retry}>Retry</button>}
          </span>
        )}
      </ArlopassHasError>
    </header>
  );
}
```

### Nesting gates

Compose gates by nesting them. Each layer handles one concern. Put negative guards inside the layout for status indicators that always show.

```tsx title="NestedGates.tsx"
import {
  ArlopassProvider,
  ArlopassConnectionGate,
  ArlopassProviderGate,
  ArlopassHasError,
} from "@arlopass/react";

function App() {
  return (
    <ArlopassProvider appId="my-app">
      {/* Layer 1: Connection */}
      <ArlopassConnectionGate
        fallback={<LoadingSpinner />}
        notInstalledFallback={<InstallPrompt />}
        errorFallback={({ error, retry }) => (
          <ErrorPage error={error} retry={retry} />
        )}
      >
        {/* Layer 2: Provider selection */}
        <ArlopassProviderGate fallback={<ProviderPicker />}>
          {/* Now fully ready for chat */}
          <AppLayout>
            <Sidebar>
              <ArlopassHasError>
                {({ error, retry }) => (
                  <ErrorBanner error={error} retry={retry} />
                )}
              </ArlopassHasError>
            </Sidebar>
            <MainContent>
              <Chat />
            </MainContent>
          </AppLayout>
        </ArlopassProviderGate>
      </ArlopassConnectionGate>
    </ArlopassProvider>
  );
}
```

### Render function on ArlopassHasError

`ArlopassHasError` uses a render function as children. It receives the error object and an optional `retry` function. Use it to build different UIs for retryable vs fatal errors.

```tsx title="HasErrorRender.tsx"
import { ArlopassHasError } from "@arlopass/react";

function StatusBar() {
  return (
    <div>
      <ArlopassHasError>
        {({ error, retry }) => {
          // Render function receives error and optional retry
          if (error.retryable) {
            return (
              <div style={{ background: "#fff3cd", padding: 8 }}>
                <span>Temporary issue: {error.message}</span>
                {retry && (
                  <button onClick={retry} style={{ marginLeft: 8 }}>
                    Retry
                  </button>
                )}
              </div>
            );
          }

          return (
            <div style={{ background: "#f8d7da", padding: 8 }}>
              <span>Fatal error: {error.message}</span>
              <span> (code: {error.machineCode})</span>
            </div>
          );
        }}
      </ArlopassHasError>
    </div>
  );
}
```

### Guards vs manual state checking

The React SDK guards replace manual if/else checking against connection and provider state:

#### React SDK

```tsx title="React SDK (guards)"
import {
  ArlopassProvider,
  ArlopassChatReadyGate,
  ArlopassHasError,
  useConversation,
} from "@arlopass/react";

function App() {
  return (
    <ArlopassProvider appId="my-app">
      <ArlopassChatReadyGate
        connectingFallback={<p>Connecting...</p>}
        providerFallback={<p>Select a provider.</p>}
        errorFallback={({ error }) => <p>Error: {error.message}</p>}
      >
        <Chat />
      </ArlopassChatReadyGate>
    </ArlopassProvider>
  );
}
```

#### Web SDK

```ts title="Web SDK (manual)"
import { ArlopassClient } from "@arlopass/web-sdk";

const client = new ArlopassClient({ transport: window.arlopass });

if (!window.arlopass) {
  showInstallPrompt();
} else {
  try {
    await client.connect({ appId: "my-app" });
  } catch (err) {
    showError(err);
  }

  if (!client.selectedProvider) {
    showProviderPicker();
  } else {
    startChat(client);
  }
}
```

