### Negative guards

Negative guards render children when a condition is **not** met. They accept `ReactNode` or a render function as children.

<ApiTable
  props={[
    {
      name: "ArlopassNotInstalled",
      type: "Component",
      description:
        "Renders children only when the Arlopass extension is not detected. Children type: ReactNode | (() => ReactNode)",
    },
    {
      name: "ArlopassDisconnected",
      type: "Component",
      description:
        'Renders children when the client is not connected (any state except "connected" or "degraded"). Children type: ReactNode | (() => ReactNode)',
    },
    {
      name: "ArlopassConnected",
      type: "Component",
      description:
        'Renders children only when connected ("connected" or "degraded"). Children type: ReactNode | (() => ReactNode)',
    },
    {
      name: "ArlopassProviderNotReady",
      type: "Component",
      description:
        "Renders children when no provider is selected. Children type: ReactNode | (() => ReactNode)",
    },
    {
      name: "ArlopassHasError",
      type: "Component",
      description:
        "Renders children when a connection error is present. Children receive { error, retry } as a render prop. Children type: (props: { error: ArlopassSDKError; retry: (() => Promise<void>) | null }) => ReactNode",
    },
    {
      name: "ArlopassChatNotReady",
      type: "Component",
      description:
        "Renders children when chat is not ready (not connected or no provider selected). Children type: ReactNode | (() => ReactNode)",
    },
    {
      name: "ArlopassChatReady",
      type: "Component",
      description:
        "Renders children only when chat is ready (connected and provider selected). Children type: ReactNode | (() => ReactNode)",
    },
  ]}
/>

